import{_ as e,o as a,i as l,ad as s}from"./chunks/framework.Cq4hg8jX.js";const p=JSON.parse('{"title":"Agent Skills","description":"用於使用與擴充 PikaCSS 的 AI 輔助開發 skill。","frontmatter":{"title":"Agent Skills","description":"用於使用與擴充 PikaCSS 的 AI 輔助開發 skill。","relatedPackages":["@pikacss/core","@pikacss/unplugin-pikacss","@pikacss/plugin-icons","@pikacss/plugin-design-tokens"],"relatedSources":["skills/pikacss-use/SKILL.md"],"category":"integrations","order":30,"translation":{"sourceFile":"docs/integrations/agent-skills.md","sourceCommit":"f0d80ceeb45331b70fcfa086aeebcacfdb5a3f8e","sourceBlob":"226d1207375d476f81c5e53f64114fd864848557"}},"headers":[],"relativePath":"zh-tw/integrations/agent-skills.md","filePath":"zh-tw/integrations/agent-skills.md"}'),t={name:"zh-tw/integrations/agent-skills.md"};function n(r,i,o,c,d,k){return a(),l("div",null,[...i[0]||(i[0]=[s('<h1 id="agent-skills" tabindex="-1">Agent Skills <a class="header-anchor" href="#agent-skills" aria-label="Permalink to “Agent Skills”">​</a></h1><p>PikaCSS 內建了一個 agent skill，為使用與擴充 PikaCSS 兩方面都提供 AI 輔助指引。你可以用 <a href="https://www.npmjs.com/package/skills" target="_blank" rel="noreferrer"><code>skills</code> CLI</a> 安裝它，並在任何支援的 coding agent 中使用。</p><h2 id="install" tabindex="-1">安裝 <a class="header-anchor" href="#install" aria-label="Permalink to “安裝”">​</a></h2><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> skills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pikacss/pikacss</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --skill</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pikacss-use</span></span></code></pre></div><h2 id="pikacss-use" tabindex="-1">pikacss-use <a class="header-anchor" href="#pikacss-use" aria-label="Permalink to “pikacss-use”">​</a></h2><h3 id="when-to-use" tabindex="-1">何時使用 <a class="header-anchor" href="#when-to-use" aria-label="Permalink to “何時使用”">​</a></h3><p>只要正在處理 PikaCSS，就可以使用這個 skill：</p><ul><li>在新專案中設定 PikaCSS</li><li>設定引擎選項或建置工具整合</li><li>使用 <code>pika()</code> 及其變體</li><li>使用官方外掛（reset、icons、fonts、typography 與 design tokens）</li><li>排解轉換、產生檔案、TypeScript 宣告或設定重新載入問題</li><li>為會載入本機資源的外掛選擇中立或 Node.js 執行階段 adapter</li><li>從頭建立新的引擎外掛</li><li>實作外掛 hook、結構化 diagnostic 與生命週期行為</li><li>透過模組擴增來擴充 <code>EngineConfig</code></li><li>註冊外部設定相依檔案，以供檔案監看</li><li>撰寫外掛測試</li></ul><h3 id="how-to-trigger" tabindex="-1">如何觸發 <a class="header-anchor" href="#how-to-trigger" aria-label="Permalink to “如何觸發”">​</a></h3><p>當問題與 PikaCSS 的使用或外掛開發相關時，這個 skill 會自動啟用。你也可以在 prompt 中明確提到「using PikaCSS」、「PikaCSS setup」或「PikaCSS plugin development」。</p><h3 id="coverage" tabindex="-1">涵蓋範圍 <a class="header-anchor" href="#coverage" aria-label="Permalink to “涵蓋範圍”">​</a></h3><ul><li>安裝與建置工具整合（Vite、Webpack、Rollup、esbuild、Rspack、Rolldown 與 Nuxt）</li><li>Node.js、Vite、來源檔案與靜態分析相容性限制</li><li>引擎設定與客製化</li><li>產生的 CSS 與 TypeScript 宣告檔案</li><li><code>pika()</code>、<code>pika.str()</code>、<code>pika.arr()</code> 與 <code>pikap()</code> 函式</li><li>官方外掛的使用與設定</li><li>中立與 Node.js 外掛進入點</li><li>ESLint 整合</li><li>TypeScript 自動完成支援</li><li>外掛結構與 <code>defineEnginePlugin</code></li><li>生命週期 hook、hook context、diagnostic 與執行順序</li><li>透過 TypeScript 模組擴增來擴充設定</li><li>layer 管理與 preflight 注入</li><li>selector、shortcut、變數、關鍵影格與 design token 的註冊</li><li>外部設定相依檔案的監看</li><li>使用 <code>createEngine</code> 的外掛測試模式</li></ul><h2 id="next" tabindex="-1">下一步 <a class="header-anchor" href="#next" aria-label="Permalink to “下一步”">​</a></h2><ul><li><a href="/zh-tw/getting-started/setup.html">安裝與設定</a>：在你的專案中安裝 PikaCSS。</li><li><a href="/zh-tw/plugin-development/create-a-plugin.html">外掛開發</a>：建立自己的外掛。</li></ul>',14)])])}const g=e(t,[["render",n]]);export{p as __pageData,g as default};
